import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL ARAYÜZ AYARLARI ---st.set_page_config(page_title="Focus AI | Eğitim Yönetim Sistemi", layout="wide", initial_sidebar_state="expanded")# --- 2. ÖSYM STRATEJİK VERİTABANI (MÜFREDAT & SORU ANALİZİ) ---MÜFREDAT = {    "TYT Matematik": {"Problemler": 12, "Sayılar": 3, "Geometri": 10, "Mantık/Kümeler": 2, "Fonksiyonlar": 1},    "AYT Matematik": {"Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2, "Limit": 2, "Diziler": 1},    "TYT Türkçe": {"Paragraf": 26, "Dil Bilgisi": 7, "Sözcükte Anlam": 7},    "AYT Edebiyat": {"Divan Edebiyatı": 5, "Cumhuriyet Dönemi": 4, "Şiir Bilgisi": 3, "Edebi Sanatlar": 2},    "TYT Fen": {"Fizik": 7, "Kimya": 7, "Biyoloji": 6},    "AYT Fen": {"Modern Fizik": 2, "Sistemler": 4, "Organik Kimya": 3, "Elektrik-Manyetizma": 3}}# --- 3. MERKEZİ VERİ TABANI (SESSION STATE) ---for key in ['ogrenciler', 'program', 'denemeler', 'soru_takip', 'ajanda', 'videolar']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Hedef", "Veli Tel"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Kaynak"])        elif key == 'soru_takip':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Ders", "Doğru", "Yanlış", "Boş"])        else:            st.session_state[key] = pd.DataFrame()# --- 4. SOL NAVİGASYON PANELİ (BAŞARION STİLİ) ---st.sidebar.title("🎯 Focus AI v6.0")st.sidebar.image("https://img.icons8.com/fluency/96/dashboard.png", width=80)st.sidebar.markdown("---")role = st.sidebar.radio("SİSTEM PANELİ", ["👨‍🏫 KOÇ / YÖNETİCİ", "🎓 ÖĞRENCİ EKRANI"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Kaydı Yok"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇ / YÖNETİCİ PANELİ# ==========================================if role == "👨‍🏫 KOÇ / YÖNETİCİ":    st.title("🏛️ Kurumsal Eğitim Yönetim Merkezi")        # Üst Bilgi Kartları    m1, m2, m3, m4 = st.columns(4)    m1.metric("Toplam Öğrenci", len(st.session_state.ogrenciler))    m2.metric("Haftalık Ödev Tamamlama", "%74", "🚀 3%")    m3.metric("Çözülen Soru (Haftalık)", "12.450", "+1200")    m4.metric("Veli Bilgilendirme", "18 Rapor", "Tamamlandı")    # BaşarıON Tarzı Sekmeli Yapı    tabs = st.tabs(["👤 Kayıt & Rehber", "📝 Ödev & Müfredat", "📊 Deneme & Radar", "🎯 Soru Takibi", "📩 Veli İletişimi"])    # --- TAB 1: KAYIT & REHBER ---    with tabs[0]:        st.subheader("👤 Öğrenci ve Veli Kayıt Yönetimi")        with st.form("kayit_form"):            c1, c2, c3 = st.columns(3)            ad = c1.text_input("Öğrenci Ad Soyad")            alan = c2.selectbox("Alan", ["Sayısal", "EA", "Sözel", "Dil"])            hedef = c3.text_input("Hedef (Bölüm/Üni)")            tel = c1.text_input("Veli Tel (905XXXXXXXXX)")            if st.form_submit_button("Sisteme Kaydet"):                yeni_o = pd.DataFrame([[ad, alan, hedef, tel]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.success("Kayıt Başarılı!")                st.rerun()        st.dataframe(st.session_state.ogrenciler, use_container_width=True)    # --- TAB 2: ÖDEV & MÜFREDAT ---    with tabs[1]:        st.subheader("📚 Müfredat ve Ödevlendirme (ÖSYM Odaklı)")        with st.form("odev_form"):            c_o, c_d, c_k = st.columns(3)            sel_o = c_o.selectbox("Öğrenci Seç", ogrenci_listesi)            sel_d = c_d.selectbox("Ders Seç", list(MÜFREDAT.keys()))            sel_k = c_k.multiselect("Konu(lar) Seç", list(MÜFREDAT[sel_d].keys()))            kaynak = st.text_input("Kaynak / Kitap Adı")            if st.form_submit_button("Ödevi Tanımla"):                for k in sel_k:                    s_y = MÜFREDAT[sel_d][k]                    yeni_p = pd.DataFrame([[sel_o, sel_d, k, s_y, "Bekliyor", kaynak]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni_p], ignore_index=True)                st.success("Ödevler Öğrenci Paneline Gönderildi!")    # --- TAB 3: DENEME & RADAR ---    with tabs[2]:        st.subheader("🕸️ Akademik Analiz ve Gelişim Radarı")        if not st.session_state.ogrenciler.empty:            sel_o_analiz = st.selectbox("Analiz Edilecek Öğrenci", ogrenci_listesi, key="analiz_sel")            col_a1, col_a2 = st.columns([2, 1])            with col_a1:                # Radar Grafik                fig = go.Figure(data=go.Scatterpolar(r=[80, 70, 90, 65, 85], theta=['Akademik', 'Odak', 'Hız', 'Mental', 'Düzen'], fill='toself'))                fig.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 100])), title=f"{sel_o_analiz} Performans Radarı")                st.plotly_chart(fig, use_container_width=True)            with col_a2:                st.write("### 📝 Koçun Notu")                st.info("Öğrencinin konu hakimiyeti yüksek ancak deneme hızı düşük. Süre tutarak branş denemesi çözmesi önerilir.")    # --- TAB 4: SORU TAKİBİ ---    with tabs[3]:        st.subheader("🎯 Günlük Soru Çözüm Analizi")        if not st.session_state.soru_takip.empty:            st.write("### Genel Soru Dağılımı")            fig_pie = px.pie(st.session_state.soru_takip, values='Doğru', names='Ders', hole=0.3)            st.plotly_chart(fig_pie, use_container_width=True)            st.dataframe(st.session_state.soru_takip, use_container_width=True)        else:            st.warning("Henüz soru verisi girilmemiş.")    # --- TAB 5: VELİ İLETİŞİMİ ---    with tabs[4]:        st.subheader("📩 WhatsApp Veli Bilgilendirme Hattı")        if not st.session_state.ogrenciler.empty:            v_o = st.selectbox("Rapor Gönderilecek Öğrenci", ogrenci_listesi, key="veli_sel")            v_tel = st.session_state.ogrenciler[st.session_state.ogrenciler["Ad Soyad"] == v_o]["Veli Tel"].values[0]            v_msg = f"Sayın Velimiz, bugün {v_o} ile yaptığımız analizde haftalık hedeflere uyum %85 saptanmıştır. Focus AI üzerinden takibimiz devam etmektedir."            st.link_button(f"🟢 WhatsApp Raporu Gönder ({v_tel})", f"https://wa.me/{v_tel}?text={v_msg.replace(' ', '%20')}")# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PANELİ# ==========================================else:    st.title("🎓 Focus AI: Öğrenci Portalı")    st.markdown(f"### Merhaba! Bugün senin için **stratejik** bir gün. 🚀")        c_o1, c_o2 = st.columns([2, 1])        with c_o1:        st.subheader("📝 Günlük Ödevlerin")        if not st.session_state.program.empty:            for i, r in st.session_state.program.iterrows():                if r["Durum"] == "Bekliyor":                    with st.expander(f"📌 {r['Ders']} | {r['Konu']} ({r['Kaynak']})"):                        st.write(f"Sınav Ağırlığı: **{r['Soru Yükü']} Soru**")                        if st.button("Tamamladım", key=i):                            st.session_state.program.at[i, "Durum"] = "Tamamlandı"                            st.rerun()        else:            st.success("Tüm ödevlerin tamamlandı! ☕")    with c_o2:        st.subheader("🎯 Soru Verisi Gir")        with st.form("soru_giris"):            s_d = st.selectbox("Ders", ["Matematik", "Türkçe", "Fen", "Sosyal"])            c_s1, c_s2, c_s3 = st.columns(3)            d = c_s1.number_input("D", 0)            y = c_s2.number_input("Y", 0)            b = c_s3.number_input("B", 0)            if st.form_submit_button("Kaydet"):                yeni_s = pd.DataFrame([[datetime.now().date(), "Öğrenci", s_d, d, y, b]], columns=st.session_state.soru_takip.columns)                st.session_state.soru_takip = pd.concat([st.session_state.soru_takip, yeni_s], ignore_index=True)                st.success("Veri koçuna iletildi!")